const body = $json.body || $json;

// Ruta típica de WhatsApp Cloud API
const value = body?.entry?.[0]?.changes?.[0]?.value;

// Si no viene la estructura esperada, cortar flujo
if (!value) {
  return [];
}

// Ignorar eventos de estados (delivered, read, sent, etc.)
if (Array.isArray(value.statuses) && value.statuses.length > 0) {
  return [];
}

// Tomar mensajes
const messages = Array.isArray(value.messages) ? value.messages : [];
if (messages.length === 0) {
  return [];
}

const msg = messages[0];

// Solo procesar mensajes entrantes con remitente
if (!msg?.from) {
  return [];
}

// Contacto si viene disponible
const contact = Array.isArray(value.contacts) ? value.contacts[0] : null;
const profileName = contact?.profile?.name || null;

// Texto normalizado según tipo
let normalizedText = '';
let attachments = [];

switch (msg.type) {
  case 'text':
    normalizedText = msg.text?.body || '';
    break;

  case 'image':
    normalizedText = msg.image?.caption || '';
    attachments.push({
      type: 'image',
      id: msg.image?.id || null,
      mime_type: msg.image?.mime_type || null,
      sha256: msg.image?.sha256 || null,
      caption: msg.image?.caption || null,
    });
    break;

  case 'document':
    normalizedText = msg.document?.caption || '';
    attachments.push({
      type: 'document',
      id: msg.document?.id || null,
      mime_type: msg.document?.mime_type || null,
      sha256: msg.document?.sha256 || null,
      filename: msg.document?.filename || null,
      caption: msg.document?.caption || null,
    });
    break;

  case 'audio':
    attachments.push({
      type: 'audio',
      id: msg.audio?.id || null,
      mime_type: msg.audio?.mime_type || null,
      sha256: msg.audio?.sha256 || null,
      voice: msg.audio?.voice || false,
    });
    break;

  case 'video':
    normalizedText = msg.video?.caption || '';
    attachments.push({
      type: 'video',
      id: msg.video?.id || null,
      mime_type: msg.video?.mime_type || null,
      sha256: msg.video?.sha256 || null,
      caption: msg.video?.caption || null,
    });
    break;

  case 'location':
    normalizedText = 'El usuario envió una ubicación';
    attachments.push({
      type: 'location',
      latitude: msg.location?.latitude || null,
      longitude: msg.location?.longitude || null,
      name: msg.location?.name || null,
      address: msg.location?.address || null,
    });
    break;

  case 'interactive':
    normalizedText =
      msg.interactive?.button_reply?.title ||
      msg.interactive?.list_reply?.title ||
      '';
    attachments.push({
      type: 'interactive',
      button_reply: msg.interactive?.button_reply || null,
      list_reply: msg.interactive?.list_reply || null,
    });
    break;

  default:
    normalizedText = '';
    attachments.push({
      type: msg.type || 'unknown',
      raw: msg,
    });
    break;
}

// Normalización final
const normalizedEvent = {
  channel: 'whatsapp',
  lead_id: msg.from,
  message_id: msg.id || null,
  timestamp: msg.timestamp || null,
  message_type: msg.type || 'unknown',
  text: normalizedText,
  attachments,
  contact: {
    wa_id: contact?.wa_id || msg.from,
    name: profileName,
  },
  source_metadata: {
    provider: 'whatsapp_cloud_api',
    phone_number_id: value?.metadata?.phone_number_id || null,
    display_phone_number: value?.metadata?.display_phone_number || null,
  },
  raw_message: msg,
};

// Si quieres ignorar todo lo que no sea texto, descomenta esto:
// if (normalizedEvent.message_type !== 'text') {
//   return [];
// }

return [
  {
    json: normalizedEvent,
  },
];

